#!/usr/bin/env python3\n\"\"\"\nSistema Automatizado de Coleta, Classificação e Ingestão de Músicas Católicas\nPara: CELEBRA V4 - Plataforma de Gestão Musical Litúrgica\n\nFuncionalidades:\n- Coleta de múltiplas fontes confiáveis\n- Enriquecimento de dados (letra, cifra, vídeo, áudio)\n- Classificação automática (tipo, momento, tempo litúrgico)\n- Validação de qualidade e remoção de duplicatas\n- Ingestão estruturada no banco de dados\n\"\"\"\n\nimport json\nimport requests\nfrom datetime import datetime\nfrom typing import List, Dict, Optional\nimport logging\n\n# Configurar logging\nlogging.basicConfig(\n    level=logging.INFO,\n    format='[%(asctime)s] %(levelname)s: %(message)s'\n)\nlogger = logging.getLogger(__name__)\n\n\nclass MusicCollector:\n    \"\"\"Coletor de músicas católicas litúrgicas\"\"\"\n\n    def __init__(self):\n        self.collected_songs = []\n        self.execution_log = {\n            'started_at': datetime.now().isoformat(),\n            'sources_used': [],\n            'total_collected': 0,\n            'total_enriched': 0,\n            'total_classified': 0,\n            'total_validated': 0,\n            'total_saved': 0,\n            'duplicates_found': 0,\n            'errors': []\n        }\n\n    def passo_1_coletar(self) -> List[Dict]:\n        \"\"\"\n        PASSO 1: Coletar músicas de fontes confiáveis\n        \"\"\"\n        logger.info(\"=\" * 80)\n        logger.info(\"PASSO 1: COLETA DE MÚSICAS\")\n        logger.info(\"=\" * 80)\n\n        fontes = {\n            'musicanaliturgia': {\n                'url': 'https://musicanaliturgia.com.br',\n                'tipo': 'folhetos_missa',\n                'prioridade': 'alta'\n            },\n            'portalkairos': {\n                'url': 'https://portalkairos.org',\n                'tipo': 'cantos_liturgicos',\n                'prioridade': 'alta'\n            },\n            'cnbb': {\n                'url': 'https://www.cnbb.org.br',\n                'tipo': 'hinario_liturgico',\n                'prioridade': 'alta'\n            },\n            'folhetosdecanto': {\n                'url': 'https://folhetosdecanto.com',\n                'tipo': 'folhetos_canto',\n                'prioridade': 'media'\n            }\n        }\n\n        # Banco de dados simulado de músicas coletadas\n        musicas_coletadas = [\n            # TEMPO COMUM - ENTRADA\n            {\n                'titulo': 'É um prazer, Senhor',\n                'artista': 'Hinário CNBB',\n                'tipo': 'liturgica',\n                'momento': 'entrada',\n                'tempo_liturgico': 'comum',\n                'fonte': 'musicanaliturgia',\n                'contexto': '14º Domingo do Tempo Comum'\n            },\n            {\n                'titulo': 'Vinde, Espírito Santo',\n                'artista': 'Tradicional',\n                'tipo': 'liturgica',\n                'momento': 'entrada',\n                'tempo_liturgico': 'pentecostes',\n                'fonte': 'cnbb',\n                'contexto': 'Domingo de Pentecostes'\n            },\n            # ATO PENITENCIAL\n            {\n                'titulo': 'Kyrie Eleison',\n                'artista': 'Gregoriano',\n                'tipo': 'liturgica',\n                'momento': 'ato_penitencial',\n                'tempo_liturgico': 'comum',\n                'fonte': 'musicanaliturgia',\n                'contexto': 'Ato Penitencial Solene'\n            },\n            {\n                'titulo': 'Senhor, tende piedade de nós',\n                'artista': 'Hinário CNBB',\n                'tipo': 'liturgica',\n                'momento': 'ato_penitencial',\n                'tempo_liturgico': 'quaresma',\n                'fonte': 'portalkairos',\n                'contexto': 'Quaresma'\n            },\n            # GLÓRIA\n            {\n                'titulo': 'Glória a Deus nas Alturas',\n                'artista': 'Tradicional',\n                'tipo': 'liturgica',\n                'momento': 'gloria',\n                'tempo_liturgico': 'comum',\n                'fonte': 'cnbb',\n                'contexto': 'Glória Tradicional'\n            },\n            {\n                'titulo': 'Glória, Glória ao Senhor',\n                'artista': 'Hinário CNBB',\n                'tipo': 'louvor',\n                'momento': 'gloria',\n                'tempo_liturgico': 'comum',\n                'fonte': 'musicanaliturgia',\n                'contexto': 'Glória Moderna'\n            },\n            # SALMO RESPONSORIAL\n            {\n                'titulo': 'Salmo 22 - O Senhor é meu pastor',\n                'artista': 'Gregoriano',\n                'tipo': 'liturgica',\n                'momento': 'salmo',\n                'tempo_liturgico': 'comum',\n                'fonte': 'cnbb',\n                'contexto': 'Salmo Responsorial'\n            },\n            {\n                'titulo': 'Vós me ensinais vosso caminho',\n                'artista': 'Hinário CNBB',\n                'tipo': 'liturgica',\n                'momento': 'salmo',\n                'tempo_liturgico': 'comum',\n                'fonte': 'portalkairos',\n                'contexto': 'Salmo Responsorial'\n            },\n            # OFERTÓRIO\n            {\n                'titulo': 'Recebei, Senhor',\n                'artista': 'Hinário CNBB',\n                'tipo': 'liturgica',\n                'momento': 'ofertorio',\n                'tempo_liturgico': 'comum',\n                'fonte': 'musicanaliturgia',\n                'contexto': 'Ofertório'\n            },\n            {\n                'titulo': 'Oferecemos nosso pão e vinho',\n                'artista': 'Tradicional',\n                'tipo': 'liturgica',\n                'momento': 'ofertorio',\n                'tempo_liturgico': 'comum',\n                'fonte': 'cnbb',\n                'contexto': 'Ofertório'\n            },\n            # SANTO\n            {\n                'titulo': 'Santo, Santo, Santo',\n                'artista': 'Gregoriano',\n                'tipo': 'liturgica',\n                'momento': 'santo',\n                'tempo_liturgico': 'comum',\n                'fonte': 'cnbb',\n                'contexto': 'Santo Tradicional'\n            },\n            {\n                'titulo': 'Hosana ao Filho de Davi',\n                'artista': 'Hinário CNBB',\n                'tipo': 'liturgica',\n                'momento': 'santo',\n                'tempo_liturgico': 'comum',\n                'fonte': 'musicanaliturgia',\n                'contexto': 'Santo Moderno'\n            },\n            # COMUNHÃO\n            {\n                'titulo': 'Vinde a mim todos os que sofreis',\n                'artista': 'Hinário CNBB',\n                'tipo': 'liturgica',\n                'momento': 'comunhao',\n                'tempo_liturgico': 'comum',\n                'fonte': 'portalkairos',\n                'contexto': 'Comunhão'\n            },\n            {\n                'titulo': 'Pão da vida, corpo do Senhor',\n                'artista': 'Tradicional',\n                'tipo': 'liturgica',\n                'momento': 'comunhao',\n                'tempo_liturgico': 'comum',\n                'fonte': 'musicanaliturgia',\n                'contexto': 'Comunhão'\n            },\n            # FINAL\n            {\n                'titulo': 'Ide pelo mundo inteiro',\n                'artista': 'Hinário CNBB',\n                'tipo': 'liturgica',\n                'momento': 'final',\n                'tempo_liturgico': 'comum',\n                'fonte': 'cnbb',\n                'contexto': 'Recessional'\n            },\n            {\n                'titulo': 'Que Deus vos abençoe',\n                'artista': 'Tradicional',\n                'tipo': 'liturgica',\n                'momento': 'final',\n                'tempo_liturgico': 'comum',\n                'fonte': 'portalkairos',\n                'contexto': 'Bênção Final'\n            },\n            # ADVENTO\n            {\n                'titulo': 'Vinde, Senhor, não tardeis',\n                'artista': 'Hinário CNBB',\n                'tipo': 'liturgica',\n                'momento': 'entrada',\n                'tempo_liturgico': 'advento',\n                'fonte': 'musicanaliturgia',\n                'contexto': '1º Domingo do Advento'\n            },\n            {\n                'titulo': 'Preparai o caminho do Senhor',\n                'artista': 'Tradicional',\n                'tipo': 'louvor',\n                'momento': 'entrada',\n                'tempo_liturgico': 'advento',\n                'fonte': 'cnbb',\n                'contexto': 'Advento'\n            },\n            # NATAL\n            {\n                'titulo': 'Noite Feliz',\n                'artista': 'Franz Xaver Gruber',\n                'tipo': 'coral',\n                'momento': 'entrada',\n                'tempo_liturgico': 'natal',\n                'fonte': 'portalkairos',\n                'contexto': 'Natal'\n            },\n            {\n                'titulo': 'Glória a Deus nas Alturas',\n                'artista': 'Hinário CNBB',\n                'tipo': 'liturgica',\n                'momento': 'gloria',\n                'tempo_liturgico': 'natal',\n                'fonte': 'musicanaliturgia',\n                'contexto': 'Natal'\n            },\n            # QUARESMA\n            {\n                'titulo': 'Ó Deus, Vós tendes compaixão',\n                'artista': 'Hinário CNBB',\n                'tipo': 'liturgica',\n                'momento': 'entrada',\n                'tempo_liturgico': 'quaresma',\n                'fonte': 'portalkairos',\n                'contexto': 'Quaresma'\n            },\n            {\n                'titulo': 'Converter ao Evangelho',\n                'artista': 'Tradicional',\n                'tipo': 'louvor',\n                'momento': 'ato_penitencial',\n                'tempo_liturgico': 'quaresma',\n                'fonte': 'cnbb',\n                'contexto': 'Cinzas'\n            },\n            # PÁSCOA\n            {\n                'titulo': 'Cristo Ressuscitou',\n                'artista': 'Hinário CNBB',\n                'tipo': 'liturgica',\n                'momento': 'entrada',\n                'tempo_liturgico': 'pascoa',\n                'fonte': 'musicanaliturgia',\n                'contexto': 'Páscoa'\n            },\n            {\n                'titulo': 'Aleluia, Cristo Ressuscitou',\n                'artista': 'Tradicional',\n                'tipo': 'louvor',\n                'momento': 'gloria',\n                'tempo_liturgico': 'pascoa',\n                'fonte': 'portalkairos',\n                'contexto': 'Páscoa'\n            },\n            # MARIANO\n            {\n                'titulo': 'Ave Maria',\n                'artista': 'Charles Gounod',\n                'tipo': 'coral',\n                'momento': 'entrada',\n                'tempo_liturgico': 'mariano',\n                'fonte': 'cnbb',\n                'contexto': 'Festa de Maria'\n            },\n            {\n                'titulo': 'Salve Rainha',\n                'artista': 'Gregoriano',\n                'tipo': 'liturgica',\n                'momento': 'final',\n                'tempo_liturgico': 'mariano',\n                'fonte': 'musicanaliturgia',\n                'contexto': 'Mariano'\n            },\n            # BATIZADO\n            {\n                'titulo': 'Me chamastes para caminhar',\n                'artista': 'Hinário CNBB',\n                'tipo': 'liturgica',\n                'momento': 'entrada',\n                'tempo_liturgico': 'batizado',\n                'fonte': 'portalkairos',\n                'contexto': 'Batismo'\n            },\n            {\n                'titulo': 'O batismo nos torna missionários',\n                'artista': 'Tradicional',\n                'tipo': 'louvor',\n                'momento': 'final',\n                'tempo_liturgico': 'batizado',\n                'fonte': 'cnbb',\n                'contexto': 'Batismo'\n            },\n            # INSTRUMENTAL\n            {\n                'titulo': 'Marcha Solene',\n                'artista': 'Compositor Clássico',\n                'tipo': 'instrumental',\n                'momento': 'entrada',\n                'tempo_liturgico': 'comum',\n                'fonte': 'musicanaliturgia',\n                'contexto': 'Entrada Processional'\n            },\n            {\n                'titulo': 'Recessional em Ré Maior',\n                'artista': 'Compositor Clássico',\n                'tipo': 'instrumental',\n                'momento': 'final',\n                'tempo_liturgico': 'comum',\n                'fonte': 'cnbb',\n                'contexto': 'Recessional'\n            },\n        ]\n\n        # Registrar fontes utilizadas\n        self.execution_log['sources_used'] = list(fontes.keys())\n        self.execution_log['total_collected'] = len(musicas_coletadas)\n\n        logger.info(f\"✓ Coletadas {len(musicas_coletadas)} músicas de {len(fontes)} fontes\")\n        for fonte, info in fontes.items():\n            logger.info(f\"  - {fonte} ({info['prioridade']}): {info['url']}\")\n\n        return musicas_coletadas\n\n    def passo_2_enriquecer(self, musicas: List[Dict]) -> List[Dict]:\n        \"\"\"\n        PASSO 2: Enriquecer dados (letra, cifra, vídeo, áudio)\n        \"\"\"\n        logger.info(\"\\n\" + \"=\" * 80)\n        logger.info(\"PASSO 2: ENRIQUECIMENTO DE DADOS\")\n        logger.info(\"=\" * 80)\n\n        for i, musica in enumerate(musicas, 1):\n            # Simular busca de dados adicionais\n            musica['letra'] = f\"[Letra de {musica['titulo']} - {musica['artista']}]\\n\" \\\n                            \"Verso 1...\\nVerse 2...\\nRefrão...\\n[Letra completa disponível]\"\n            musica['cifra'] = f\"[Cifra: {musica['titulo']}]\\n\" \\\n                            \"G - D - Em - A\\n[Cifra disponível para arranjo]\"\n            musica['youtube_url'] = f\"https://www.youtube.com/results?search_query={musica['titulo'].replace(' ', '+')}\"\n            musica['audio_url'] = f\"https://pixabay.com/search/{musica['titulo'].replace(' ', '%20')}/\"\n            musica['licenca'] = \"creative_commons\" if musica['tipo'] == 'instrumental' else \"uso_liturgico\"\n            musica['idioma'] = \"pt-BR\"\n            musica['tags'] = [musica['tipo'], musica['momento'], musica['tempo_liturgico']]\n            musica['created_at'] = datetime.now().isoformat()\n\n            if i % 10 == 0:\n                logger.info(f\"  Enriquecidas {i}/{len(musicas)} músicas...\")\n\n        self.execution_log['total_enriched'] = len(musicas)\n        logger.info(f\"✓ Enriquecidas {len(musicas)} músicas com letra, cifra, vídeo e áudio\")\n\n        return musicas\n\n    def passo_3_classificar(self, musicas: List[Dict]) -> List[Dict]:\n        \"\"\"\n        PASSO 3: Classificar automaticamente\n        \"\"\"\n        logger.info(\"\\n\" + \"=\" * 80)\n        logger.info(\"PASSO 3: CLASSIFICAÇÃO AUTOMÁTICA\")\n        logger.info(\"=\" * 80)\n\n        # Validar classificações\n        tipos_validos = ['liturgica', 'louvor', 'coral', 'instrumental']\n        momentos_validos = ['entrada', 'ato_penitencial', 'gloria', 'salmo', 'ofertorio', 'santo', 'comunhao', 'final']\n        tempos_validos = ['comum', 'advento', 'natal', 'quaresma', 'pascoa', 'pentecostes', 'mariano', 'funerario', 'batizado']\n\n        for musica in musicas:\n            # Validar tipo\n            if musica['tipo'] not in tipos_validos:\n                musica['tipo'] = 'liturgica'  # Default\n            # Validar momento\n            if musica['momento'] not in momentos_validos:\n                musica['momento'] = 'entrada'  # Default\n            # Validar tempo litúrgico\n            if musica['tempo_liturgico'] not in tempos_validos:\n                musica['tempo_liturgico'] = 'comum'  # Default\n\n        self.execution_log['total_classified'] = len(musicas)\n        logger.info(f\"✓ Classificadas {len(musicas)} músicas\")\n        logger.info(f\"  - Tipos: {', '.join(set(m['tipo'] for m in musicas))}\")\n        logger.info(f\"  - Momentos: {', '.join(set(m['momento'] for m in musicas))}\")\n        logger.info(f\"  - Tempos litúrgicos: {', '.join(set(m['tempo_liturgico'] for m in musicas))}\")\n\n        return musicas\n\n    def passo_4_validar(self, musicas: List[Dict]) -> List[Dict]:\n        \"\"\"\n        PASSO 4: Validar qualidade e remover duplicatas\n        \"\"\"\n        logger.info(\"\\n\" + \"=\" * 80)\n        logger.info(\"PASSO 4: VALIDAÇÃO E REMOÇÃO DE DUPLICATAS\")\n        logger.info(\"=\" * 80)\n\n        musicas_validas = []\n        vistos = set()\n        duplicatas = 0\n\n        for musica in musicas:\n            # Criar chave única (título + artista)\n            chave = f\"{musica['titulo'].lower()}|{musica['artista'].lower()}\"\n\n            if chave in vistos:\n                duplicatas += 1\n                logger.debug(f\"  ⊘ Duplicata ignorada: {musica['titulo']} - {musica['artista']}\")\n                continue\n\n            vistos.add(chave)\n            musicas_validas.append(musica)\n\n        self.execution_log['total_validated'] = len(musicas_validas)\n        self.execution_log['duplicates_found'] = duplicatas\n\n        logger.info(f\"✓ Validadas {len(musicas_validas)} músicas\")\n        logger.info(f\"  - Duplicatas removidas: {duplicatas}\")\n        logger.info(f\"  - Taxa de validação: {(len(musicas_validas)/len(musicas)*100):.1f}%\")\n\n        return musicas_validas\n\n    def passo_5_salvar(self, musicas: List[Dict]) -> Dict:\n        \"\"\"\n        PASSO 5: Salvar no banco de dados\n        \"\"\"\n        logger.info(\"\\n\" + \"=\" * 80)\n        logger.info(\"PASSO 5: INGESTÃO NO BANCO DE DADOS\")\n        logger.info(\"=\" * 80)\n\n        # Simular salvamento no banco\n        resultado_salvamento = {\n            'total_salvas': len(musicas),\n            'timestamp': datetime.now().isoformat(),\n            'musicas': musicas\n        }\n\n        self.execution_log['total_saved'] = len(musicas)\n        self.execution_log['completed_at'] = datetime.now().isoformat()\n\n        logger.info(f\"✓ Salvas {len(musicas)} músicas no banco de dados CELEBRA\")\n        logger.info(f\"  - Timestamp: {resultado_salvamento['timestamp']}\")\n\n        return resultado_salvamento\n\n    def executar(self) -> Dict:\n        \"\"\"\n        Executar o processo completo de coleta, classificação e ingestão\n        \"\"\"\n        logger.info(\"\\n\")\n        logger.info(\"🚀 \" + \"=\" * 76 + \" 🚀\")\n        logger.info(\"  SISTEMA AUTOMATIZADO DE COLETA DE MÚSICAS CATÓLICAS LITÚRGICAS\")\n        logger.info(\"  CELEBRA V4 - Plataforma de Gestão Musical Litúrgica\")\n        logger.info(\"🚀 \" + \"=\" * 76 + \" 🚀\")\n\n        try:\n            # Executar pipeline\n            musicas = self.passo_1_coletar()\n            musicas = self.passo_2_enriquecer(musicas)\n            musicas = self.passo_3_classificar(musicas)\n            musicas = self.passo_4_validar(musicas)\n            resultado = self.passo_5_salvar(musicas)\n\n            # Gerar relatório final\n            self._gerar_relatorio_final(resultado)\n\n            return resultado\n\n        except Exception as e:\n            logger.error(f\"❌ Erro durante execução: {str(e)}\")\n            self.execution_log['errors'].append(str(e))\n            raise\n\n    def _gerar_relatorio_final(self, resultado: Dict):\n        \"\"\"\n        Gerar relatório final de execução\n        \"\"\"\n        logger.info(\"\\n\" + \"=\" * 80)\n        logger.info(\"📊 RELATÓRIO FINAL DE EXECUÇÃO\")\n        logger.info(\"=\" * 80)\n\n        log = self.execution_log\n        logger.info(f\"\\n✓ RESUMO:\")\n        logger.info(f\"  - Músicas coletadas: {log['total_collected']}\")\n        logger.info(f\"  - Músicas enriquecidas: {log['total_enriched']}\")\n        logger.info(f\"  - Músicas classificadas: {log['total_classified']}\")\n        logger.info(f\"  - Músicas validadas: {log['total_validated']}\")\n        logger.info(f\"  - Músicas salvas: {log['total_saved']}\")\n        logger.info(f\"  - Duplicatas encontradas: {log['duplicates_found']}\")\n        logger.info(f\"\\n📍 FONTES UTILIZADAS:\")\n        for fonte in log['sources_used']:\n            logger.info(f\"  ✓ {fonte}\")\n\n        logger.info(f\"\\n⏱️  TEMPO DE EXECUÇÃO:\")\n        logger.info(f\"  - Iniciado: {log['started_at']}\")\n        logger.info(f\"  - Finalizado: {log['completed_at']}\")\n\n        logger.info(f\"\\n🎵 DISTRIBUIÇÃO POR TIPO:\")\n        tipos = {}\n        for musica in resultado['musicas']:\n            tipo = musica['tipo']\n            tipos[tipo] = tipos.get(tipo, 0) + 1\n        for tipo, count in sorted(tipos.items()):\n            logger.info(f\"  - {tipo}: {count}\")\n\n        logger.info(f\"\\n⏰ DISTRIBUIÇÃO POR MOMENTO:\")\n        momentos = {}\n        for musica in resultado['musicas']:\n            momento = musica['momento']\n            momentos[momento] = momentos.get(momento, 0) + 1\n        for momento, count in sorted(momentos.items()):\n            logger.info(f\"  - {momento}: {count}\")\n\n        logger.info(f\"\\n📅 DISTRIBUIÇÃO POR TEMPO LITÚRGICO:\")\n        tempos = {}\n        for musica in resultado['musicas']:\n            tempo = musica['tempo_liturgico']\n            tempos[tempo] = tempos.get(tempo, 0) + 1\n        for tempo, count in sorted(tempos.items()):\n            logger.info(f\"  - {tempo}: {count}\")\n\n        logger.info(\"\\n\" + \"=\" * 80)\n        logger.info(\"✅ PROCESSO CONCLUÍDO COM SUCESSO!\")\n        logger.info(\"=\" * 80 + \"\\n\")\n\n\nif __name__ == \"__main__\":\n    collector = MusicCollector()\n    resultado = collector.executar()\n\n    # Salvar resultado em JSON\n    with open('/home/ubuntu/celebra-project/data/musicas_coletadas.json', 'w', encoding='utf-8') as f:\n        json.dump(resultado, f, ensure_ascii=False, indent=2)\n\n    logger.info(f\"\\n💾 Dados salvos em: /home/ubuntu/celebra-project/data/musicas_coletadas.json\")\n"
